class Solution {
public:
    long long findMaximumNumber(long long k, int x) {
        long long left = 0, right = k * x;
        while (left < right) {
            long long mid = (left + right + 1) / 2;
            if (getPrice(mid, x) <= k) left = mid;
            else right = mid - 1;
        }
        return left;
    }

    long long getPrice(long long num, int x) {
        long long price = 0;
        for (long long i = x; i <= sizeof(long long) * 8; i += x) {
            long long mask = (1LL << i) - 1;
            long long fullCycle = (num + 1) / (1LL << i);
            long long partialCycle = (num + 1) % (1LL << i);
            price += fullCycle * (1LL << (i - 1));
            price += (partialCycle > mask ? (1LL << (i - 1)) : (partialCycle & mask));
        }
        return price;
    }
};
